#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define REC_LENGTH 53 
#define LATITUDE_POS 28	
#define OPEN 10000	

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

__kernel void euclid(__global const LatLong *d_locations, __global float *d_distances, int numRecords, float lat, float lng)
{
    size_t globalId = get_global_id(0);
    if (globalId < (size_t)numRecords) {
        LatLong latLong = d_locations[globalId];
        float dist = sqrt((lat - latLong.lat)*(lat - latLong.lat) + (lng - latLong.lng)*(lng - latLong.lng));
        d_distances[globalId] = dist;
    }
}
